{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Back2Key_N2N\par}
{\pard \ql \f0 \sa180 \li0 \fi0 MIDI note transposer where C=0.\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Slider 1: Semitone shift using C as the reference (C=0).\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Slider 2: Octave shift (Down / No Change / Up).\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Auto octave clamp: if transposed note is <0 or >127, it is shifted by octaves (\u177 ?12) until in range.\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Note-off is matched to the note-on even if sliders change while notes are held.\sa180\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Bass_Assign_N2N\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Pass only note-ons with velocity 90 on MIDI channel 2. Passes all note-offs and all MIDI on other channels.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
